//! Dump first row of blk.0.attn_v.weight (Q6_K) to compare with gguf-py.
//! Reference: row 0 first 16 = [-0.0157, -0.0175, 0.0084, -0.0139, ...]

use distributed_inference::loader::KnotWeights;
use distributed_inference::math::{dequantize_q4k_row, dequantize_q6k_row, mat_vec_q6k_row};

fn main() -> Result<(), String> {
    let path = std::env::args().nth(1).expect("usage: q6k-row-dump <knot>");
    let knot = KnotWeights::load(&path).map_err(|e| format!("load: {:?}", e))?;
    let info = knot
        .metadata
        .get("blk_0_attn_v_weight")
        .ok_or("missing blk_0_attn_v_weight metadata".to_string())?;
    println!(
        "info: type={} length={} offset={}",
        info.tensor_type, info.length, info.offset
    );
    let bytes = knot
        .backend
        .fetch_tensor("blk_0_attn_v_weight")
        .map_err(|e| format!("fetch: {:?}", e))?;
    println!("fetched {} bytes", bytes.len());
    // hidden_dim=3584. Row 0.
    let mut row = vec![0f32; 3584];
    dequantize_q6k_row(&mut row, &bytes, 0, 3584);
    println!("row 0 first 16:");
    for (i, v) in row.iter().take(16).enumerate() {
        println!("  [{:>2}] {:.6}", i, v);
    }
    let max = row.iter().fold(0f32, |a, &b| a.max(b.abs()));
    let mean = row.iter().map(|v| v.abs()).sum::<f32>() / row.len() as f32;
    println!("row 0 max_abs={:.6} mean_abs={:.6}", max, mean);

    // Now Q4_K: blk.0.attn_q.weight (3584 cols, 3584 rows)
    let q_bytes = knot
        .backend
        .fetch_tensor("blk_0_attn_q_weight")
        .map_err(|e| format!("fetch q: {:?}", e))?;
    let mut q_row = vec![0f32; 3584];
    dequantize_q4k_row(&mut q_row, &q_bytes, 0, 3584);
    println!("\n[Q4_K] blk.0.attn_q.weight row 0 first 16:");
    for (i, v) in q_row.iter().take(16).enumerate() {
        println!("  [{:>2}] {:.6}", i, v);
    }
    let qmax = q_row.iter().fold(0f32, |a, &b| a.max(b.abs()));
    let qmean = q_row.iter().map(|v| v.abs()).sum::<f32>() / q_row.len() as f32;
    println!("Q4_K row 0 max_abs={:.6} mean_abs={:.6}", qmax, qmean);

    // Now sanity-check Q6_K matmul: compute V[0] = sum(input × dequant_row_0).
    // First a synthetic input: all 1.0
    let ones = vec![1.0f32; 3584];
    let dequant_dot: f32 = row.iter().zip(ones.iter()).map(|(a, b)| a * b).sum();
    let bpr = 3584 / 256; // 14 blocks per row
    let row_ptr = bytes.as_ptr();
    let matmul_out = mat_vec_q6k_row(&ones, row_ptr, bpr);
    println!("\n[Q6_K matmul check] input=ones, blk.0.attn_v.weight row 0:");
    println!("  dequant·ones (manual): {:.6}", dequant_dot);
    println!("  mat_vec_q6k_row:        {:.6}", matmul_out);
    println!("  ratio: {:.4}", matmul_out / dequant_dot);
    Ok(())
}
